from __future__ import annotations

from dataclasses import dataclass
from typing import Iterable


class CronParseError(ValueError):
    """Raised when a cron expression is invalid."""


@dataclass(frozen=True)
class FieldSpec:
    name: str
    minimum: int
    maximum: int


@dataclass(frozen=True)
class CronField:
    spec: FieldSpec
    raw: str
    values: tuple[int, ...]

    @property
    def is_wildcard(self) -> bool:
        return self.values == tuple(range(self.spec.minimum, self.spec.maximum + 1))

    @property
    def single_value(self) -> int | None:
        return self.values[0] if len(self.values) == 1 else None


@dataclass(frozen=True)
class CronSchedule:
    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        if all(field.is_wildcard for field in self.fields()):
            return "Every minute"

        if (
            self.minute.raw.startswith("*/")
            and self.hour.is_wildcard
            and self.day_of_month.is_wildcard
            and self.month.is_wildcard
            and self.day_of_week.is_wildcard
        ):
            step = parse_positive_int(self.minute.raw[2:], "minute step")
            return f"Every {step} minutes"

        if (
            self.minute.single_value == 0
            and self.hour.raw.startswith("*/")
            and self.day_of_month.is_wildcard
            and self.month.is_wildcard
            and self.day_of_week.is_wildcard
        ):
            step = parse_positive_int(self.hour.raw[2:], "hour step")
            return f"Every {step} hours, on the hour"

        time_text = describe_time(self.hour, self.minute)
        date_parts = describe_date_parts(self.day_of_month, self.month, self.day_of_week)

        if date_parts:
            return f"{time_text} {', '.join(date_parts)}"

        return time_text

    def fields(self) -> tuple[CronField, CronField, CronField, CronField, CronField]:
        return (
            self.minute,
            self.hour,
            self.day_of_month,
            self.month,
            self.day_of_week,
        )


FIELD_SPECS: tuple[FieldSpec, ...] = (
    FieldSpec("minute", 0, 59),
    FieldSpec("hour", 0, 23),
    FieldSpec("day_of_month", 1, 31),
    FieldSpec("month", 1, 12),
    FieldSpec("day_of_week", 0, 6),
)

DAY_NAMES: dict[int, str] = {
