    12: "December",
}


def parse_cron(expression: str) -> CronSchedule:
    parts = expression.split()

    if len(parts) != 5:
        raise CronParseError(
            f"Expected 5 cron fields, got {len(parts)}: {expression!r}"
        )

    minute, hour, day_of_month, month, day_of_week = (
        parse_field(raw, spec) for raw, spec in zip(parts, FIELD_SPECS)
    )

    return CronSchedule(
        minute=minute,
        hour=hour,
        day_of_month=day_of_month,
        month=month,
        day_of_week=day_of_week,
    )


def parse_field(raw: str, spec: FieldSpec) -> CronField:
    if not raw:
        raise CronParseError(f"{spec.name} field cannot be empty")

    values: set[int] = set()

    for item in raw.split(","):
        if not item:
            raise CronParseError(f"{spec.name} field contains an empty list item")
        values.update(parse_field_item(item, spec))

    if not values:
        raise CronParseError(f"{spec.name} field produced no values")

    return CronField(spec=spec, raw=raw, values=tuple(sorted(values)))


def parse_field_item(item: str, spec: FieldSpec) -> tuple[int, ...]:
    if "/" not in item:
        return parse_base_item(item, spec)

    base_text, step_text = split_step(item, spec)
    step = parse_positive_int(step_text, f"{spec.name} step")
    base_values = parse_base_item(base_text, spec)

    return base_values[::step]


def parse_base_item(item: str, spec: FieldSpec) -> tuple[int, ...]:
    if item == "*":
        return tuple(range(spec.minimum, spec.maximum + 1))

    if "-" in item:
        start_text, end_text = split_range(item, spec)
        start = parse_value(start_text, spec)
        end = parse_value(end_text, spec)

        if start > end:
            raise CronParseError(
                f"{spec.name} range start must be <= end: {item!r}"
            )

        return tuple(range(start, end + 1))

    return (parse_value(item, spec),)


def split_step(item: str, spec: FieldSpec) -> tuple[str, str]:
    parts = item.split("/")

    if len(parts) != 2 or not parts[0] or not parts[1]:
        raise CronParseError(f"Invalid {spec.name} step expression: {item!r}")

    return parts[0], parts[1]


def split_range(item: str, spec: FieldSpec) -> tuple[str, str]:
    parts = item.split("-")

    if len(parts) != 2 or not parts[0] or not parts[1]:
        raise CronParseError(f"Invalid {spec.name} range expression: {item!r}")

    return parts[0], parts[1]


def parse_value(text: str, spec: FieldSpec) -> int:
    value = parse_int(text, spec.name)

    if value < spec.minimum or value > spec.maximum:
        raise CronParseError(
            f"{spec.name} value {value} is outside allowed range "
            f"{spec.minimum}-{spec.maximum}"
        )

    return value


def parse_positive_int(text: str, label: str) -> int:
    value = parse_int(text, label)

    if value <= 0:
        raise CronParseError(f"{label} must be greater than zero")

    return value


def parse_int(text: str, label: str) -> int:
    if not text.isdigit():
        raise CronParseError(f"{label} must be an integer: {text!r}")

    return int(text)


def describe_time(hour: CronField, minute: CronField) -> str:
    if hour.single_value is not None and minute.single_value is not None:
        if hour.single_value == 0 and minute.single_value == 0:
            return "At midnight"
        return f"At {hour.single_value:02d}:{minute.single_value:02d}"

    if hour.is_wildcard and minute.single_value is not None:
        return f"At {minute.single_value} minutes past every hour"

    if minute.single_value == 0:
        return f"On the hour during {describe_numeric_field(hour)}"

    return f"At minute {describe_numeric_field(minute)} during {describe_numeric_field(hour)}"


def describe_date_parts(
    day_of_month: CronField,
    month: CronField,
    day_of_week: CronField,
) -> list[str]:
    parts: list[str] = []

    if not day_of_week.is_wildcard:
        parts.append(f"on {describe_day_of_week(day_of_week)}")

    if not day_of_month.is_wildcard:
        parts.append(f"on the {describe_day_of_month(day_of_month)} of every month")

    if not month.is_wildcard:
        parts.append(f"in {describe_month(month)}")

    return parts


def describe_day_of_week(field: CronField) -> str:
    return describe_named_field(field, DAY_NAMES)


def describe_month(field: CronField) -> str:
    return describe_named_field(field, MONTH_NAMES)


def describe_named_field(field: CronField, names: dict[int, str]) -> str:
    if is_simple_range(field.raw):
        start, end = parse_range_numbers(field.raw)
        return f"{names[start]} through {names[end]}"

    return join_english(names[value] for value in field.values)


def describe_day_of_month(field: CronField) -> str:
    return join_english(ordinal(value) for value in field.values)


def describe_numeric_field(field: CronField) -> str:
    if field.is_wildcard:
        return f"every {field.spec.name}"

    if is_simple_range(field.raw):
        start, end = parse_range_numbers(field.raw)
        return f"{start} through {end}"

    return join_english(str(value) for value in field.values)


def is_simple_range(raw: str) -> bool:
    return "," not in raw and "/" not in raw and "-" in raw


def parse_range_numbers(raw: str) -> tuple[int, int]:
    start_text, end_text = raw.split("-", maxsplit=1)
    return int(start_text), int(end_text)


def join_english(items: Iterable[str]) -> str:
    values = list(items)

    if len(values) == 1:
        return values[0]

    if len(values) == 2:
        return f"{values[0]} and {values[1]}"

    return f"{', '.join(values[:-1])}, and {values[-1]}"


def ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")

    return f"{value}{suffix}"
